Javascript.logic:
var thisCourtToExecute = Services.getValue(ThisCourtToExecute.dataBinding);
if (!CaseManUtils.isBlank(thisCourtToExecute))
{
	if (thisCourtToExecute == 'N')
	{
		Services.dispatchEvent("SelectVenue_Popup", PopupGUIAdaptor.EVENT_RAISE);
	}
	else
	{
		getOwningCourtData();
	}
}

