			OracleReportForm.refDataServices = 
			[
				{name:"Courts", dataBinding:REF_DATA_XPATH, serviceName:"getCourts", serviceParams:[]}
			];
			
			var NEW_HEARING_VENUE_TMP_PATH = "/ds/var/page/Tmp/Venue";
			var NEW_HEARING_TMP_PATH = "/ds/var/page/Tmp/Hearing";		
			
			function SelectVenue_Popup(){}
			SelectVenue_Popup.nextFocusedAdaptorId = function()
			{ 
				return 'SelectVenue_VenueLOVBtn';   //force framework to move to next available field
			}
		
