			function selectVenue_Address_Grid() {};
			
			SelectVenue_VenueCode.dataBinding = NEW_HEARING_VENUE_TMP_PATH + "/VenueCode";
			SelectVenue_VenueName.dataBinding = NEW_HEARING_VENUE_TMP_PATH + "/VenueName";
			SelectVenue_ContactDetails_Address_Line1.dataBinding = NEW_HEARING_VENUE_TMP_PATH + "/Address/Line[1]";
			SelectVenue_ContactDetails_Address_Line2.dataBinding = NEW_HEARING_VENUE_TMP_PATH + "/Address/Line[2]";
			SelectVenue_ContactDetails_Address_Line3.dataBinding = NEW_HEARING_VENUE_TMP_PATH + "/Address/Line[3]";
			SelectVenue_ContactDetails_Address_Line4.dataBinding = NEW_HEARING_VENUE_TMP_PATH + "/Address/Line[4]";
			SelectVenue_ContactDetails_Address_Line5.dataBinding = NEW_HEARING_VENUE_TMP_PATH + "/Address/Line[5]";
			SelectVenue_ContactDetails_Address_Postcode.dataBinding = NEW_HEARING_VENUE_TMP_PATH + "/Address/PostCode";
			SelectVenue_ContactDetails_Address_DXNumber.dataBinding = NEW_HEARING_VENUE_TMP_PATH + "/DXNumber";
			SelectVenue_ContactDetails_Address_TelephoneNumber.dataBinding = NEW_HEARING_VENUE_TMP_PATH + "/TelephoneNumber";
			SelectVenue_ContactDetails_Address_FaxNumber.dataBinding = NEW_HEARING_VENUE_TMP_PATH + "/FaxNumber";
			selectVenue_Address_Grid.dataBinding = "/ds/var/page/SelectedGridRow/SelectedAddress"; // will use this below to bind fields correctly to correct bit of xml
			
			/**********************************************************************************/
			
			function CourtsLOVGrid() {};
			CourtsLOVGrid.dataBinding = "/ds/var/page/SelectedLOVRow/OwningCourt";
			CourtsLOVGrid.srcData = REF_DATA_XPATH + "/Courts";
			CourtsLOVGrid.rowXPath = "Court";
			CourtsLOVGrid.keyXPath = "Id";
			CourtsLOVGrid.columns = [
				{xpath: "Code"},
				{xpath: "Name"}
			];
			CourtsLOVGrid.raise = {
				eventBinding: {
					singleClicks: [ {element: "SelectVenue_VenueLOVBtn"} ],
					keys: [ { key: Key.F6, element: "SelectVenue_VenueCode" }, { key: Key.F6, element: "SelectVenue_VenueName" } ]
				}
			};
			
			// Configure the location in the model which will generate data change events
			CourtsLOVGrid.logicOn = [CourtsLOVGrid.dataBinding];
			// Implement the callback
			CourtsLOVGrid.logic = function()
			{
				var id = Services.getValue(CourtsLOVGrid.dataBinding);
				if (id != null)
				{
					// Lookup the hearing type in ref data from the code that is stored in value
					var xpathCode = REF_DATA_XPATH + "/Courts/Court[Id = " + id + "]/Code";		
					var xpathName = REF_DATA_XPATH + "/Courts/Court[Id = " + id + "]/Name";		
					var courtCode = Services.getValue(xpathCode);
					var courtName = Services.getValue(xpathName);
					
					// Set the data in the business part of the model
					Services.setValue(SelectVenue_VenueCode.dataBinding, courtCode);
					Services.setValue(SelectVenue_VenueName.dataBinding, courtName);		
				}
			} // end of logic()
			
			/**********************************************************************************/
			
			SelectVenue_VenueCode.tabIndex = __tabIdx++;
			SelectVenue_VenueCode.isTemporary = function() { return true; }
			SelectVenue_VenueCode.maxLength = 3;
			SelectVenue_VenueCode.helpText = "Unique three digit court location code - list available.";
			SelectVenue_VenueCode.isMandatory = function() { return true; }
			
			SelectVenue_VenueCode.logicOn = [SelectVenue_VenueCode.dataBinding];
			SelectVenue_VenueCode.logic = function()
			{
				var code = Services.getValue(SelectVenue_VenueCode.dataBinding);
				var xpathName = REF_DATA_XPATH + "/Courts/Court[./Code = " + SelectVenue_VenueCode.dataBinding + "]/Name";
				var xpathId = REF_DATA_XPATH + "/Courts/Court[./Code = " + SelectVenue_VenueCode.dataBinding + "]/Id";
				var venueName = Services.getValue(xpathName);
				var venueId = Services.getValue(xpathId);
			
				// Set the data in the business part of the model
				if ( !CaseManUtils.isBlank(venueName) )
				{
					// set the description field appropriately
					Services.setValue(SelectVenue_VenueName.dataBinding, venueName);		
					Services.setValue(CourtsLOVGrid.dataBinding, venueId);		
				}
				else
				{
					// Clear the fields
					Services.setValue(SelectVenue_VenueName.dataBinding, "");
				}
			} // end of logic()
			
			SelectVenue_VenueCode.validateOn = [SelectVenue_VenueCode.dataBinding,
												SelectVenue_VenueName.dataBinding];
			SelectVenue_VenueCode.validate = function()
			{
				var venueCode = Services.getValue(SelectVenue_VenueCode.dataBinding);	
				var errCode = null;
				if ( !CaseManUtils.isBlank(venueCode) )
				{				
					if ( !Services.exists(REF_DATA_XPATH + "/Courts/Court[./Code = " + SelectVenue_VenueCode.dataBinding + "]") )
					{
						errCode = ErrorCode.getErrorCode('CaseMan_invalidCourtCode_Msg');
					}	
				}	
				return errCode;
			}
			
			/**********************************************************************************/
			
			SelectVenue_VenueName.tabIndex = __tabIdx++;
			SelectVenue_VenueName.isTemporary = function(){ return true; }
			SelectVenue_VenueName.helpText = "Name of the Court.";
			SelectVenue_VenueName.isMandatory = function(){ return true; }
			SelectVenue_VenueName.strictValidation = true;
			SelectVenue_VenueName.srcData = REF_DATA_XPATH + "/Courts";
			SelectVenue_VenueName.rowXPath = "Court";
			SelectVenue_VenueName.keyXPath = "Name";
			SelectVenue_VenueName.displayXPath = "Name";
			SelectVenue_VenueName.logicOn  = [SelectVenue_VenueName.dataBinding];
			SelectVenue_VenueName.logic = function()
			{ 
				var name = Services.getValue(SelectVenue_VenueName.dataBinding);
				var xpathId = REF_DATA_XPATH + "/Courts/Court[./Name = " + SelectVenue_VenueName.dataBinding + "]/Code";
				var code = Services.getValue(xpathId);
				if( !CaseManUtils.isBlank(code) )
				{
					Services.setValue(SelectVenue_VenueCode.dataBinding, code);
				}
				else
				{ 
					Services.setValue(SelectVenue_VenueCode.dataBinding, "");
				}
			}
			
			/**********************************************************************************/
			
			SelectVenue_ContactDetails_Address_Line1.tabIndex = -1;
			SelectVenue_ContactDetails_Address_Line1.isReadOnly = function()  {	return true;}
			SelectVenue_ContactDetails_Address_Line1.isTemporary = function() {	return true;}
			SelectVenue_ContactDetails_Address_Line1.isMandatory = function() {	return true;}
			SelectVenue_ContactDetails_Address_Line1.transformToDisplay = function(value) {
				return (null != value) ? value.toUpperCase() : null; }
			SelectVenue_ContactDetails_Address_Line1.transformToModel = function(value) {
				return (null != value) ? value.toUpperCase() : null; }
			
