			SelectVenue_ContactDetails_Address_DXNumber.tabIndex = -1;
			SelectVenue_ContactDetails_Address_DXNumber.isReadOnly = function() {return true;}
			
			/**********************************************************************************/
			
			function SelectVenue_ContactDetails_Address_FaxNumber() {}
			SelectVenue_ContactDetails_Address_FaxNumber.tabIndex = -1;
			SelectVenue_ContactDetails_Address_FaxNumber.isReadOnly = function() { 	return true;}
			
			/**********************************************************************************/
			
			function SelectVenue_VenueLOVBtn() {}
			SelectVenue_VenueLOVBtn.tabIndex = __tabIdx++;
			
			/**********************************************************************************/
			
			function SelectVenue_OKBtn() {}
			SelectVenue_OKBtn.tabIndex = __tabIdx++;
			SelectVenue_OKBtn.enableOn = [SelectVenue_VenueCode.dataBinding, SelectVenue_VenueName.dataBinding, SelectVenue_ContactDetails_Address_Line1.dataBinding, SelectVenue_ContactDetails_Address_Line2.dataBinding];
			SelectVenue_OKBtn.isEnabled = function()
			{
				var blnEnabled = false;
				
				// Get field values
				var courtCode = Services.getValue(SelectVenue_VenueCode.dataBinding);
				var courtName = Services.getValue(SelectVenue_VenueName.dataBinding);
				var adline1 = Services.getValue(SelectVenue_ContactDetails_Address_Line1.dataBinding);
				var adline2 = Services.getValue(SelectVenue_ContactDetails_Address_Line2.dataBinding);
				
				if ( !CaseManUtils.isBlank(courtCode) && !CaseManUtils.isBlank(courtName) && 
					 !CaseManUtils.isBlank(adline1) && !CaseManUtils.isBlank(adline2) )
				{
					// Determine if fields are valid
					var courtCodeValid = Services.getAdaptorById("SelectVenue_VenueCode").getValid();
					var courtNameValid = Services.getAdaptorById("SelectVenue_VenueName").getValid();
					
					if ( courtCodeValid && courtNameValid )
					{
						// Only enabled if all mandatory fields are entered and are valid (CaseMan Defect 6010)
						blnEnabled = true;
					}
				}
				return blnEnabled;
			}
				
			SelectVenue_OKBtn.actionBinding = function()
			{
				if ( SelectVenue_OKBtn.isEnabled() )
				{
					var courtName = Services.getValue(REF_DATA_XPATH + "/Courts/Court[./Code = " + SelectVenue_VenueCode.dataBinding + "]/Name");
					if ( !CaseManUtils.isBlank(courtName) )   
					{  
						// Valid court code entered, set the court name field
						Services.setValue(NameOfCourt.dataBinding, courtName);
					}
					Services.dispatchEvent("SelectVenue_Popup", BusinessLifeCycleEvents.EVENT_LOWER);
				}
			}
			
			/**********************************************************************************/
			
			function SelectVenue_CancelBtn() {}
			SelectVenue_CancelBtn.tabIndex = __tabIdx++;
			SelectVenue_CancelBtn.additionalBindings = {
				eventBinding: {
					keys: [ { key: Key.F4, element: "SelectVenue_Popup" } ]
				}
			};
			SelectVenue_CancelBtn.actionBinding = function()
			{
				Services.dispatchEvent("SelectVenue_Popup", BusinessLifeCycleEvents.EVENT_LOWER);
				Services.setValue(ThisCourtToExecute.dataBinding, "Y");
			}
			
			/**********************************************************************************/
			
			// Configure grid
			selectVenue_Address_Grid.srcData = REF_DATA_XPATH + "/Courts/Court[./Id = " + CourtsLOVGrid.dataBinding + "]/ContactDetails"; //List of Courts/venues addresses
			selectVenue_Address_Grid.rowXPath = "Address";		// Individual Court/venue
			selectVenue_Address_Grid.keyXPath = "AddressId";  	// Unique identifier for a Court/venue
			selectVenue_Address_Grid.columns = [   				// column bindings
				{xpath: "Line[1]"},
				{xpath: "Line[2]"}
			];
			
			selectVenue_Address_Grid.retrieveOn = [CourtsLOVGrid.dataBinding];
			selectVenue_Address_Grid.srcDataOn = [CourtsLOVGrid.dataBinding];
			
			// When  a different Address row is selected
			selectVenue_Address_Grid.logicOn = [selectVenue_Address_Grid.dataBinding,
												CourtsLOVGrid.dataBinding];
			
			// Get the associated Address Data
			selectVenue_Address_Grid.logic = function()
			{
				var courtId = Services.getValue(CourtsLOVGrid.dataBinding);
				var addressId = Services.getValue(selectVenue_Address_Grid.dataBinding);
				if (courtId != null && addressId != null){
					// Set the address details as necessary.
					// Set up xpaths
					var b11 = REF_DATA_XPATH + "/Courts/Court[./Id = ";
					var b13 = "]/ContactDetails/";
					var b12 = b13 + "Address[./AddressId = ";
					var xpathAdd1 = b11 + courtId + b12 + addressId + "]/Line[1]";	
					var xpathAdd2 = b11  + courtId + b12 + addressId + "]/Line[2]";	
					var xpathAdd3 = b11  + courtId + b12 + addressId + "]/Line[3]";	
					var xpathAdd4 = b11  + courtId + b12 + addressId + "]/Line[4]";	
					var xpathAdd5 = b11  + courtId + b12 + addressId + "]/Line[5]";	
					var xpathPostcode = b11  + courtId + b12 + addressId + "]/PostCode";	
					var xpathDXNo  = b11 + courtId + b13 +"DX";	
					var xpathTelNo = b11 + courtId + b13 +"TelephoneNumber";	
					var xpathFaxNo = b11 + courtId + b13 +"FaxNumber";	
					
					// retrieve values from the DOM
					var add1 = Services.getValue(xpathAdd1);
					var add2 = Services.getValue(xpathAdd2);
					// ensure not adding a null - as these fields are not mandatory		
					var add3 = Services.getValue(xpathAdd3);
					if(add3 == null){add3 = "";	}	
					var add4 = Services.getValue(xpathAdd4);
					if(add3 == null){add4 = "";}
					var add5 = Services.getValue(xpathAdd5);
					if(add3 == null){add5 = "";	}
					var postcode = Services.getValue(xpathPostcode);		
					var dxNo = Services.getValue(xpathDXNo);
					if(dxNo == null){dxNo = "";	}
					var telNo = Services.getValue(xpathTelNo);
					if(telNo == null){	telNo = "";	}
					var faxNo = Services.getValue(xpathFaxNo);
					if(telNo == null){telNo= "";}
					
					// Set the data in the tmp part of the model
					Services.setValue(SelectVenue_ContactDetails_Address_Line1.dataBinding, add1);
					Services.setValue(SelectVenue_ContactDetails_Address_Line2.dataBinding, add2);
					Services.setValue(SelectVenue_ContactDetails_Address_Line3.dataBinding, add3);
					Services.setValue(SelectVenue_ContactDetails_Address_Line4.dataBinding, add4);
					Services.setValue(SelectVenue_ContactDetails_Address_Line5.dataBinding, add5);
					Services.setValue(SelectVenue_ContactDetails_Address_Postcode.dataBinding, postcode);		
					Services.setValue(SelectVenue_ContactDetails_Address_DXNumber.dataBinding, dxNo);
					Services.setValue(SelectVenue_ContactDetails_Address_TelephoneNumber.dataBinding, telNo);
					Services.setValue(SelectVenue_ContactDetails_Address_FaxNumber.dataBinding, faxNo);		
				}
			} // end of logic()
			
			/**********************************************************************************/	
			
			function getOwningCourtData()
			{
				var courtCode = Services.getValue(VAR_PAGE_XPATH + "/tmp/OwningCourtCode");
				var params = new ServiceParams();
				params.addSimpleParameter("courtId", courtCode);
				var node = Services.getNode(REF_DATA_XPATH + "/OwningCourt");
				if (node == null)
				{
					Services.callService("getCourt", params, getOwningCourtData, true);
				}
			}		

			getOwningCourtData.onSuccess = function(dom)
			{
				//debugger;
				if(dom != null) 
				{
					var results = dom.selectSingleNode("/Courts");
					if(results != null) 
					{
						Services.addNode(results, REF_DATA_XPATH + "/OwningCourt");
					}
					else 
					{
						this.onError();
					}
				}
				else 
				{
					this.onError();
				}				
			}
			
			getOwningCourtData.onError = function()
			{
				alert("Failed to get Court Data for your Court");
			}
